                    <div class="attribute-value" id="modal-intelligence">-</div>
                </div>
            </div>

            <!-- 妖精契约区域 -->
            <div id="fairy-section" style="display: none;">
                <div class="section-title">妖精契约</div>
                <div class="character-grid">
                    <div class="avatar-preview">
                        <img id="modal-fairy-avatar" src="https://files.catbox.moe/p9h9a5.png" alt="妖精头像">
                    </div>
                    <div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-signature"></i> 姓名:</div>
                            <div class="info-value" id="modal-fairy-name">-</div>
                        </div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-birthday-cake"></i> 年龄:</div>
                            <div class="info-value" id="modal-fairy-age">-</div>
                        </div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-eye"></i> 外貌:</div>
                            <div class="info-value" id="modal-fairy-appearance">-</div>
                        </div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-ruler-vertical"></i> 身高:</div>
                            <div class="info-value" id="modal-fairy-height">-</div>
                        </div>
                    </div>
                    <div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-user"></i> 身材:</div>
                            <div class="info-value" id="modal-fairy-figure">-</div>
                        </div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-tshirt"></i> 服装:</div>
                            <div class="info-value" id="modal-fairy-costumes">-</div>
                        </div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-smile"></i> 性格:</div>
                            <div class="info-value" id="modal-fairy-personality">-</div>
                        </div>
                        <div class="info-item">
                            <div class="info-label"><i class="fas fa-magic"></i> 元素魔法:</div>
                            <div class="info-value" id="modal-fairy-magic">-</div>
                        </div>
                    </div>
                </div>
            </div>

            <button class="recruit-btn" id="recruit-btn">
                <i class="fas fa-handshake"></i> 招募此成员
            </button>
        </div>
    </div>

    <!-- 通知区域 -->
    <div id="notification-area"></div>

    <script>
        // 优化后的成员数据
        const recruitData = `
$1
        `;

        // 全局变量
        let selectedMembers = [];
        let allMembers = [];

        // 页面加载完成后初始化
        document.addEventListener('DOMContentLoaded', function() {
            // 关闭模态框
            document.getElementById('close-modal').addEventListener('click', function() {
                document.getElementById('member-modal').classList.remove('active');
            });

            // 图片加载错误处理
            document.querySelectorAll('img').forEach(img => {
                img.onerror = function() {
                    this.src = 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="100" height="100" viewBox="0 0 100 100"><rect width="100%" height="100%" fill="%23f0f0f0"/><text x="50%" y="50%" font-size="14" text-anchor="middle" fill="%23999" dy=".3em">加载失败</text></svg>';
                };
            });

            // 单个招募按钮事件
            document.getElementById('recruit-btn').addEventListener('click', function() {
                const memberName = document.getElementById('modal-member-name').textContent;
                recruitSingleMember(memberName);
                document.getElementById('member-modal').classList.remove('active');
            });

            // 多人招募按钮事件
            document.getElementById('multi-recruit-btn').addEventListener('click', recruitMultipleMembers);

            // 选择控制按钮
            document.getElementById('select-all-btn').addEventListener('click', selectAllMembers);
            document.getElementById('deselect-all-btn').addEventListener('click', deselectAllMembers);
            document.getElementById('invert-selection-btn').addEventListener('click', invertSelection);

            // 解析并生成招募成员列表
            allMembers = parseRecruitData(recruitData);
            generateRecruitList(allMembers);
            updateSelectedCount();
        });

        // 招募单个成员
        function recruitSingleMember(memberName) {
            const message = `招募${memberName}`;
            try {
                triggerSlash(`/send ${message} |/trigger`);
                showNotification(`成功招募 ${memberName}！消息已发送。`, 'success');
            } catch (error) {
                showNotification(`模拟执行：发送消息"${message}"`, 'success');
                console.log('模拟执行命令:', `/send ${message} |/trigger`);
            }
        }

        // 招募多个成员
        function recruitMultipleMembers() {
            if (selectedMembers.length === 0) {
                showNotification('请先选择要招募的成员！', 'error');
                return;
            }

            const memberNames = selectedMembers.map(member => member['姓名']).join('、');
            const message = `招募${memberNames}`;

            try {
                triggerSlash(`/send ${message} |/trigger`);
                showNotification(`成功招募 ${selectedMembers.length} 名成员！消息已发送。`, 'success');
            } catch (error) {
                showNotification(`模拟执行：发送消息"${message}"`, 'success');
                console.log('模拟执行命令:', `/send ${message} |/trigger`);
            }

            // 清空选择
            deselectAllMembers();
        }

        // 全选成员
        function selectAllMembers() {
            selectedMembers = [...allMembers];
            updateSelectionUI();
            updateSelectedCount();
        }

        // 取消全选
        function deselectAllMembers() {
            selectedMembers = [];
            updateSelectionUI();
            updateSelectedCount();
        }

        // 反选成员
        function invertSelection() {
            const newSelected = allMembers.filter(member => 
                !selectedMembers.includes(member)
            );
            selectedMembers = newSelected;
            updateSelectionUI();
            updateSelectedCount();
        }

        // 更新选中数量显示
        function updateSelectedCount() {
            document.getElementById('selected-count').textContent = selectedMembers.length;
        }

        // 更新选择UI
        function updateSelectionUI() {
            document.querySelectorAll('.member-card').forEach((card, index) => {
                const checkbox = card.querySelector('.member-selector input');
                if (checkbox) {
                    checkbox.checked = selectedMembers.includes(allMembers[index]);
                }

                if (selectedMembers.includes(allMembers[index])) {
                    card.style.border = '2px solid var(--success-color)';
                    card.style.boxShadow = '0 0 15px rgba(46, 204, 113, 0.5)';
                } else {
                    card.style.border = '2px solid var(--recruit-secondary)';
                    card.style.boxShadow = '0 4px 8px rgba(0,0,0,0.1)';
                }
            });
        }

        // 显示通知
        function showNotification(message, type = 'success') {
            const notificationArea = document.getElementById('notification-area');
            const notification = document.createElement('div');
            notification.className = `notification ${type}`;
            notification.textContent = message;
            notificationArea.appendChild(notification);

            setTimeout(() => {
                notification.classList.add('show');
                setTimeout(() => notification.remove(), 3000);
            }, 100);
        }

        // 正则表达式解析函数
        function parseRecruitData(input) {
            const regex = /<([^>]+)>(.*?)<\/\1>/gs;
            const members = [];
            let currentMember = null;
            let currentFairy = null;
            let match;

            while ((match = regex.exec(input)) !== null) {
                const tag = match[1].trim();
                const value = match[2].trim();

                if (tag === '招募成员图片链接') {
                    if (currentMember) {
                        if (currentFairy) {
                            currentMember.fairy = currentFairy;
                            currentFairy = null;
                        }
                        members.push(currentMember);
                    }
                    currentMember = {};
                    currentMember.avatar = value;
                }
                else if (tag === '契约妖精头像链接') {
                    currentFairy = {};
                    currentFairy.avatar = value;
                }
                else if (currentMember) {
                    if (currentFairy && tag !== '契约妖精头像链接') {
                        currentFairy[tag] = value;
                    } 
                    else {
                        currentMember[tag] = value;
                    }
                }
            }

            if (currentMember) {
                if (currentFairy) {
                    currentMember.fairy = currentFairy;
                }
                members.push(currentMember);
            }

            return members;
        }

        // 生成招募成员列表
        function generateRecruitList(members) {
            const recruitGrid = document.getElementById('recruit-grid');
            const recruitCounter = document.getElementById('recruit-counter');

            recruitGrid.innerHTML = '';
            recruitCounter.textContent = members.length;

            if (members.length === 0) {
                recruitGrid.innerHTML = '<div class="no-team">未找到招募成员数据</div>';
                return;
            }

            members.forEach((member, index) => {
                const card = document.createElement('div');
                card.className = 'member-card';
                card.dataset.index = index;

                const fairyIndicator = member.fairy ? 
                    `<div class="fairy-indicator" title="妖精契约"><i class="fas fa-fairy"></i></div>` : '';

                const strengthVal = member['力量'] || '0';
                const agilityVal = member['敏捷'] || '0';
                const staminaVal = member['耐力'] || '0';
                const intelligenceVal = member['智力'] || '0';

                card.innerHTML = `
                    <div class="member-selector">
                        <input type="checkbox" class="member-checkbox" data-index="${index}">
                    </div>
                    ${fairyIndicator}
                    <div class="member-header">
                        <div class="member-avatar">
                            <img src="${member.avatar || '#'}" alt="${member['姓名']}">
                        </div>
                        <div>
                            <div class="member-name">${member['姓名'] || '未知成员'}</div>
                            ${!member.fairy ? 
                                `<div class="no-contract-notice">
                                    <i class="fas fa-times-circle"></i> 没有妖精契约
                                </div>` : 
                                ''}
                        </div>
                    </div>
                    <div class="recruit-info">
                        <div>
                            <div class="info-label-small">等级</div>
                            <div class="info-value-small">${member['冒险者等级'] || '-'}</div>
                        </div>
                        <div>
                            <div class="info-label-small">职位</div>
                            <div class="info-value-small">${member['职位'] || '-'}</div>
                        </div>
                        <div>
                            <div class="info-label-small">种族</div>
                            <div class="info-value-small">${member['种族'] || '-'}</div>
                        </div>
                        <div>
                            <div class="info-label-small">性别</div>
                            <div class="info-value-small">${member['性别'] || '-'}</div>
                        </div>
                    </div>
                    <div class="core-stats">
                        <div class="stat-card strength">
                            <div class="stat-label-small">力量</div>
                            <div class="stat-value">${strengthVal}</div>
                        </div>
                        <div class="stat-card agility">
                            <div class="stat-label-small">敏捷</div>
                            <div class="stat-value">${agilityVal}</div>
                        </div>
                        <div class="stat-card stamina">
                            <div class="stat-label-small">耐力</div>
                            <div class="stat-value">${staminaVal}</div>
                        </div>
                        <div class="stat-card intelligence">
                            <div class="stat-label-small">智力</div>
                            <div class="stat-value">${intelligenceVal}</div>
                        </div>
                    </div>
                    <div class="stat-chips">
                        <div class="stat-chip strength-chip">
                            <i class="fas fa-fist-raised stat-icon"></i>
                            <span>${strengthVal}</span>
                        </div>
                        <div class="stat-chip agility-chip">
                            <i class="fas fa-running stat-icon"></i>
                            <span>${agilityVal}</span>
                        </div>
                        <div class="stat-chip stamina-chip">
                            <i class="fas fa-heartbeat stat-icon"></i>
                            <span>${staminaVal}</span>
                        </div>
                        <div class="stat-chip intelligence-chip">
                            <i class="fas fa-brain stat-icon"></i>
                            <span>${intelligenceVal}</span>
                        </div>
                    </div>
                `;

                recruitGrid.appendChild(card);

                // 绑定点击事件
                card.addEventListener('click', (e) => {
                    if (!e.target.closest('.member-selector')) {
                        loadMemberDetails(member);
                        document.getElementById('member-modal').classList.add('active');
                    }
                });

                // 绑定选择框事件
                const checkbox = card.querySelector('.member-checkbox');
                checkbox.addEventListener('click', (e) => {
                    e.stopPropagation();
                    const index = parseInt(checkbox.dataset.index);
                    const member = allMembers[index];

                    if (checkbox.checked) {
                        if (!selectedMembers.includes(member)) {
                            selectedMembers.push(member);
                        }
                    } else {
                        selectedMembers = selectedMembers.filter(m => m !== member);
                    }

                    updateSelectionUI();
                    updateSelectedCount();
                });
            });
        }

        // 加载成员详情
        function loadMemberDetails(member) {
            document.getElementById('modal-name').textContent = member['姓名'] || '-';
            document.getElementById('modal-race').textContent = member['种族'] || '-';
            document.getElementById('modal-gender').textContent = member['性别'] || '-';
            document.getElementById('modal-age').textContent = member['年龄'] || '-';
            document.getElementById('modal-level').textContent = member['冒险者等级'] || '-';
            document.getElementById('modal-position').textContent = member['职位'] || '-';
            document.getElementById('modal-height').textContent = member['身高'] || '-';
            document.getElementById('modal-face').textContent = member['长相'] || '-';
            document.getElementById('modal-figure').textContent = member['身材'] || '-';
            document.getElementById('modal-costumes').textContent = member['服饰'] || '-';
            document.getElementById('modal-appearance').textContent = member['外观'] || '-';
            document.getElementById('modal-race-features').textContent = member['种族特点'] || '-';
            document.getElementById('modal-personality').textContent = member['性格'] || '-';
            document.getElementById('modal-member-name').textContent = member['姓名'] || '成员详情';

            document.getElementById('modal-strength').textContent = member['力量'] || '-';
            document.getElementById('modal-agility').textContent = member['敏捷'] || '-';
            document.getElementById('modal-stamina').textContent = member['耐力'] || '-';
            document.getElementById('modal-intelligence').textContent = member['智力'] || '-';

            const avatarImg = document.getElementById('modal-avatar');
            avatarImg.src = member.avatar || 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="100" height="100" viewBox="0 0 100 100"><rect width="100%" height="100%" fill="%23f0f0f0"/><text x="50%" y="50%" font-size="14" text-anchor="middle" fill="%23999" dy=".3em">无头像</text></svg>';

            const fairySection = document.getElementById('fairy-section');
            if (member.fairy) {
                fairySection.style.display = 'block';
                document.getElementById('modal-fairy-name').textContent = member.fairy['姓名'] || '-';
                document.getElementById('modal-fairy-age').textContent = member.fairy['年龄'] || '-';
                document.getElementById('modal-fairy-appearance').textContent = member.fairy['外貌'] || '-';
                document.getElementById('modal-fairy-height').textContent = member.fairy['身高'] || '-';
                document.getElementById('modal-fairy-figure').textContent = member.fairy['身材'] || '-';
                document.getElementById('modal-fairy-costumes').textContent = member.fairy['服装'] || '-';
                document.getElementById('modal-fairy-personality').textContent = member.fairy['性格'] || '-';
                document.getElementById('modal-fairy-magic').textContent = member.fairy['元素魔法'] || '-';

                const fairyAvatar = document.getElementById('modal-fairy-avatar');
                fairyAvatar.src = member.fairy.avatar || 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/ssvg" width="100" height="100" viewBox="0 0 100 100"><rect width="100%" height="100%" fill="%23f0f0f0"/><text x="50%" y="50%" font-size="14" text-anchor="middle" fill="%23999" dy=".3em">无头像</text></svg>';
            } else {
                fairySection.style.display = 'none';
            }
        }
    </script>
