    <script>
        // 任务数据存储
        let tasks = [];
        const taskContainer = document.getElementById('task-container');
        const taskDetail = document.getElementById('task-detail');
        const taskInput = document.getElementById('task-input');
        const parseBtn = document.getElementById('parse-btn');

        // 解析XML格式的任务数据（不需要在<任务公告板>中）
        function parseTasksFromXML(xmlData) {
            const newTasks = [];
            const taskRegex = /<任务>([\s\S]*?)<\/任务>/g;
            let taskMatch;

            // 循环提取每个<任务>块
            while ((taskMatch = taskRegex.exec(xmlData)) !== null) {
                const taskBlock = taskMatch[1];

                // 使用非贪婪匹配提取各个字段
                const nameMatch = taskBlock.match(/<任务名字>([\s\S]*?)<\/任务名字>/);
                const objectiveMatch = taskBlock.match(/<任务目标>([\s\S]*?)<\/任务目标>/);
                const suggestionMatch = taskBlock.match(/<任务建议>([\s\S]*?)<\/任务建议>/);  // 修改为任务建议
                const rankMatch = taskBlock.match(/<任务等级>([\s\S]*?)<\/任务等级>/);
                const rewardMatch = taskBlock.match(/<任务报酬>([\s\S]*?)<\/任务报酬>/);
                const publisherMatch = taskBlock.match(/<任务发布人>([\s\S]*?)<\/任务发布人>/); // 新增任务发布人

                // 确保所有必填字段都存在
                if (nameMatch && objectiveMatch && rankMatch && rewardMatch) {
                    newTasks.push({
                        name: nameMatch[1].trim(),
                        objective: objectiveMatch[1].trim(),
                        suggestion: suggestionMatch ? suggestionMatch[1].trim() : '无特殊建议', // 修改为任务建议
                        rank: rankMatch[1].trim().toUpperCase(),
                        reward: rewardMatch[1].trim(),
                        publisher: publisherMatch ? publisherMatch[1].trim() : '冒险家协会'    // 新增任务发布人
                    });
                }
            }
            return newTasks;
        }

        // 初始化任务列表显示
        function initTaskList() {
            taskContainer.innerHTML = '';

            if (tasks.length === 0) {
                taskContainer.innerHTML = '<div class="no-tasks">暂无任务</div>';
                return;
            }

            tasks.forEach((task, index) => {
                createTaskCard(task, index);
            });
        }

        // 创建任务卡片
        function createTaskCard(task, index) {
            const card = document.createElement('div');
            card.className = 'task-card';
            card.dataset.index = index;

            card.innerHTML = `
                <div class="task-card-header">
                    <div class="task-name">${task.name}</div>
                    <div class="task-rank rank-${task.rank.toLowerCase()}">${task.rank}</div>
                </div>
                <div class="task-publisher">发布人：${task.publisher}</div>
                <div class="task-reward">${task.reward}</div>
            `;

            card.addEventListener('click', () => {
                showTaskDetail(task);
            });

            taskContainer.appendChild(card);
        }

        // 显示任务详情
        function showTaskDetail(task) {
            taskDetail.style.display = 'block';
            taskDetail.innerHTML = `
                <div class="detail-header">
                    <div class="detail-title">${task.name}</div>
                    <div class="close-btn" id="close-detail">×</div>
                </div>
                <div class="detail-content">
                    <div class="detail-section">
                        <div class="detail-label">任务目标</div>
                        <div class="detail-value">${task.objective}</div>
                    </div>
                    <div class="detail-section">
                        <div class="detail-label">任务建议</div>
                        <div class="detail-value">${task.suggestion}</div>
                    </div>
                    <div class="detail-section">
                        <div class="detail-label">任务发布人</div>
                        <div class="detail-value">${task.publisher}</div>
                    </div>
                    <div class="detail-section">
                        <div class="detail-label">任务等级</div>
                        <div class="detail-value">
                            <span class="task-rank rank-${task.rank.toLowerCase()}">${task.rank}</span>
                        </div>
                    </div>
                    <div class="detail-section">
                        <div class="detail-label">任务报酬</div>
                        <div class="detail-value">${task.reward}</div>
                    </div>
                </div>
            `;

            // 添加关闭按钮事件
            document.getElementById('close-detail').addEventListener('click', () => {
                taskDetail.style.display = 'none';
            });
        }

        // 页面加载完成后自动执行
        document.addEventListener('DOMContentLoaded', () => {
            // 设置输入框内容为示例数据
            taskInput.value = `$1`;

            // 自动解析示例数据
            setTimeout(() => {
                if (taskInput.value.trim() !== '') {
                    tasks = parseTasksFromXML(taskInput.value);
                    if (tasks.length > 0) {
                        initTaskList();

                        // 自动展开第一个任务详情
                        setTimeout(() => {
                            if (tasks.length > 0) {
                                showTaskDetail(tasks[0]);
                            }
                        }, 300);
                    }
                }
            }, 500);
        });
    </script>
</body>
</html>
