        .attribute-label {
            font-size: 1.1rem;
            color: var(--primary);
        }

        .input-section {
            background: var(--input-bg);
            padding: 20px;
            border-radius: 20px;
            margin-bottom: 25px;
            border: 2px dashed var(--primary);
        }

        .generate-btn {
            background: linear-gradient(135deg, #2e7d32, #388e3c);
            margin-top: 15px;
        }

        .member-count {
            margin: 15px 0;
            font-weight: bold;
            color: var(--accent);
            font-size: 16px;
        }

        /* 自动加载通知 */
        .auto-load-notice {
            background: rgba(157, 41, 51, 0.1);
            border-left: 4px solid var(--accent);
            padding: 12px 20px;
            margin: 15px 0;
            font-family: 'Comic Sans MS', cursive;
            text-align: center;
            border-radius: 10px;
            font-size: 1.1rem;
        }

        .hidden {
            display: none;
        }

        .numeric-value {
            font-weight: bold;
            color: var(--accent);
        }

        /* 骨架屏 */
        .skeleton-card {
            background: rgba(255, 255, 255, 0.8);
            border-radius: 20px;
            padding: 25px;
            margin-bottom: 25px;
            height: 250px;
            position: relative;
            overflow: hidden;
        }

        .skeleton-line {
            height: 25px;
            background: rgba(0, 0, 0, 0.08);
            border-radius: 5px;
            margin-bottom: 15px;
            width: 80%;
        }

        .skeleton-line.short {
            width: 60%;
        }

        .skeleton-line.avatar {
            width: 80px;
            height: 80px;
            border-radius: 50%;
            margin: 0 auto 15px;
        }

        .skeleton-animation {
            position: absolute;
            top: 0;
            left: -100%;
            width: 100%;
            height: 100%;
            background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.4), transparent);
            animation: skeletonLoading 1.5s infinite;
        }

        @keyframes skeletonLoading {
            100% { left: 100%; }
        }

        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(20px); }
            to { opacity: 1; transform: translateY(0); }
        }

        /* 响应式设计 */
        @media (max-width: 768px) {
            .character-grid {
                grid-template-columns: 1fr;
