            .member-stats {
                grid-template-columns: 1fr;
                gap: 5px;
            }

            .info-label, .info-value {
                font-size: 0.85rem;
            }

            .progress-bar {
                height: 18px;
            }

            .progress-text {
                font-size: 0.8rem;
            }

            .fairy-status {
                font-size: 0.7rem;
                padding: 2px 20px;
                right: -32px;
                top: 8px;
            }

            .affection-container {
                grid-column: auto;
            }
        }

        /* 超超窄屏幕适配 (小于280px) */
        @media (max-width: 280px) {
            .header-bar {
                flex-direction: column;
                gap: 10px;
            }

