                font-size: 0.75rem;
            }

            .info-value {
                font-size: 0.85rem;
                padding: 8px;
            }

            .progress-bar {
                height: 16px;
            }

            .progress-text {
                font-size: 0.7rem;
            }

            .fairy-status {
