            }

            .fairy-btn {
                padding: 10px 20px;
                font-size: 0.9rem;
            }

            .attribute-value {
                font-size: 1.8rem;
            }

            .attribute-label {
                font-size: 0.9rem;
            }
        }

        /* 队员卡片 - 适配窄屏 */
        .member-card {
            position: relative;
            overflow: visible;
        }

        /* 契约状态标签 - 位置优化 */
        .fairy-status {
            position: absolute;
