                const details = document.getElementById('fairy-details');
                details.classList.toggle('active');
                this.querySelector('i').className = details.classList.contains('active') ? 
                    'fas fa-chevron-up' : 'fas fa-chevron-down';
            });

            // 关闭模态框
            document.getElementById('close-modal').addEventListener('click', function() {
                document.getElementById('member-modal').classList.remove('active');
            });

            // 新增生成按钮事件
            const generateBtn = document.getElementById('generate-btn');
            const dataInput = document.getElementById('data-input');
            const memberCount = document.getElementById('member-count');

            generateBtn.addEventListener('click', function() {
                const inputData = dataInput.value;
                if (!inputData.trim()) {
                    memberCount.textContent = "错误: 输入数据为空";
                    return;
                }

                const members = parseMemberData(inputData);
                memberCount.textContent = `检测到: ${members.length} 名队员`;
                generateTeam(members);
            });

            // 输入框实时检测
            dataInput.addEventListener('input', function() {
                const inputData = this.value;
                if (!inputData.trim()) {
                    memberCount.textContent = "检测到: 0 名队员";
                    return;
                }

                const members = parseMemberData(inputData);
                memberCount.textContent = `检测到: ${members.length} 名队员`;
            });

            // 自动加载预定义数据
            const predefinedData = document.getElementById('predefined-data').value;
            if (predefinedData.trim()) {
                const members = parseMemberData(predefinedData);

                // 模拟加载延迟
                setTimeout(() => {
                    generateTeam(members);
                }, 1500);

                // 隐藏输入区域
                document.getElementById('input-section').classList.add('hidden');
            }
        });

        // 正则表达式解析函数（修复背景故事显示问题）
        function parseMemberData(input) {
            const regex = /<([^>]+)>(.*?)<\/\1>/gs;
            const members = [];
            let currentMember = null;
            let currentFairy = null;
            let match;

            // 标签映射 - 修复背景故事标签不一致的问题
            const tagMapping = {
                '背景': '背景',
                '背景故事': '背景'
            };

            while ((match = regex.exec(input)) !== null) {
                let tag = match[1].trim();
                const value = match[2].trim();

                // 应用标签映射
                if (tagMapping[tag]) {
                    tag = tagMapping[tag];
                }

                // 队员开始标记
                if (tag === '队员头像链接') {
                    // 保存上一个队员
                    if (currentMember) {
                        if (currentFairy) {
                            currentMember.fairy = currentFairy;
                            currentFairy = null;
                        }
                        members.push(currentMember);
                    }
                    currentMember = {};
                    currentMember.avatar = value;
                }
                // 契约妖精开始标记
                else if (tag === '契约妖精头像链接') {
                    currentFairy = {};
                    currentFairy.avatar = value;
                }
                // 普通属性
                else if (currentMember) {
                    // 如果是契约妖精的属性
                    if (currentFairy && tag !== '契约妖精头像链接') {
                        currentFairy[tag] = value;
                    } 
                    // 如果是队员的属性
                    else {
                        currentMember[tag] = value;
                    }
                }
            }

            // 处理最后一个队员
            if (currentMember) {
                if (currentFairy) {
                    currentMember.fairy = currentFairy;
                }
                members.push(currentMember);
            }

            return members;
        }

        // 队伍生成函数
        function generateTeam(members) {
            const teamGrid = document.getElementById('team-grid');
            const teamCounter = document.getElementById('team-counter');

            // 清空现有内容
            teamGrid.innerHTML = '';
            teamCounter.textContent = members.length;

            if (members.length === 0) {
                teamGrid.innerHTML = '<div class="no-team">未解析到有效队员数据</div>';
                return;
            }

            // 生成队员卡片
            members.forEach((member, index) => {
                const memberId = index;
                const card = document.createElement('div');
                card.className = 'member-card';
                card.setAttribute('data-member', memberId);

                // 处理百分比值
                const getPercentValue = (val) => {
                    if (!val) return 0;
                    if (val.includes('%')) {
                        return parseInt(val.replace('%', '')) || 0;
                    }
                    return parseInt(val) || 0;
                };

                const hpPercent = getPercentValue(member['生命值']);
                const loyaltyPercent = getPercentValue(member['忠诚度']);
                const affectionPercent = getPercentValue(member['好感度']);

                // 添加契约指示器 - 使用修复后的标签样式
                const fairyTag = member.fairy ? 
                    '<div class="fairy-status has-fairy">内有妖精</div>' : 
                    '<div class="fairy-status no-fairy">内无妖精</div>';

                card.innerHTML = `
                    ${fairyTag}
                    <div class="member-header">
                        <div>
                            <div class="member-name">${member['姓名'] || '未知队员'}</div>
                            <div class="info-value">
                                ${member['种族'] || '未知种族'} · ${member['职业'] || '未知职业'}
                            </div>
                        </div>
                    </div>
                    <div class="member-stats">
                        <div>
                            <div class="info-label"><i class="fas fa-heart"></i> 生命值</div>
                            <div class="info-value">
                                <div class="progress-bar">
                                    <div class="progress-fill" style="width: ${hpPercent}%"></div>
                                    <div class="progress-text">${hpPercent}%</div>
                                </div>
                            </div>
                        </div>
                        <div>
                            <div class="info-label"><i class="fas fa-shield-alt"></i> 忠诚度</div>
                            <div class="info-value">
                                <div class="progress-bar">
                                    <div class="progress-fill" style="width: ${loyaltyPercent}%"></div>
                                    <div class="progress-text">${loyaltyPercent}%</div>
                                </div>
                            </div>
                        </div>
                        <div class="affection-container">
                            <div class="info-label"><i class="fas fa-heartbeat"></i> 好感度</div>
                            <div class="info-value">
                                <div class="progress-bar">
                                    <div class="progress-fill" style="width: ${affectionPercent}%"></div>
                                    <div class="progress-text">${affectionPercent}%</div>
                                </div>
                            </div>
                        </div>
                    </div>
                `;

                teamGrid.appendChild(card);

                // 绑定点击事件
                card.addEventListener('click', () => {
                    loadMemberDetails(member);
                    document.getElementById('member-modal').classList.add('active');
                });
            });
        }

        // 加载队员详情
        function loadMemberDetails(member) {
            // 更新基本信息
            document.getElementById('modal-name').textContent = member['姓名'] || '-';
            document.getElementById('modal-race').textContent = member['种族'] || '-';
            document.getElementById('modal-gender').textContent = member['性别'] || '-';
            document.getElementById('modal-measurements').textContent = member['三围'] || '-';
            document.getElementById('modal-appearance').textContent = member['外貌'] || '-';
            document.getElementById('modal-level').textContent = member['冒险者等级'] || '-';
            document.getElementById('modal-class').textContent = member['职业'] || '-';

            // 修复背景故事显示问题
            const background = member['背景'] || member['背景故事'] || '-';
            document.getElementById('modal-background').textContent = background;

            document.getElementById('modal-strength').textContent = member['力量'] || '-';
            document.getElementById('modal-agility').textContent = member['敏捷'] || '-';
            document.getElementById('modal-stamina').textContent = member['耐力'] || '-';
            document.getElementById('modal-intelligence').textContent = member['智力'] || '-';
            document.getElementById('modal-member-name').textContent = member['姓名'] || '队员详情';

            // 获取精灵契约区域
            const fairySection = document.getElementById('fairy-section');

            // 更新精灵契约信息（如果有契约）
            if (member.fairy) {
                // 显示精灵契约区域
                fairySection.style.display = 'block';

                // 更新精灵契约信息
                document.getElementById('modal-fairy-name').textContent = member.fairy['姓名'] || '-';
                document.getElementById('modal-fairy-age').textContent = member.fairy['年龄'] || '-';
                document.getElementById('modal-fairy-appearance').textContent = member.fairy['外貌'] || '-';
                document.getElementById('modal-fairy-height').textContent = member.fairy['身高'] || '-';
                document.getElementById('modal-fairy-figure').textContent = member.fairy['身材'] || '-';
                document.getElementById('modal-fairy-costumes').textContent = member.fairy['服装'] || '-';
                document.getElementById('modal-fairy-personality').textContent = member.fairy['性格'] || '-';
                document.getElementById('modal-fairy-magic').textContent = member.fairy['元素魔法'] || '-';
            } else {
                // 隐藏精灵契约区域
                fairySection.style.display = 'none';
            }
        }
    </script>
</body>
</html>
